	.SBTTL	GRACAMEMB; Flags pour D2 dans DRTRANCHE; ----------------------------BDRTDD	=	16		; dessine la droite DdBDRTDA	=	17		; dessine la droite DaBDRT12	=	18		; dessine dans les cadrants I et IIBDRT34	=	19		; dessine dans les cadrants III et IV;--------\\; DESGCAM >;========/; Dessine un graphique en camembert (miam).; in	-; out	D7.W	erreur; mod	D7.WDESGCAM:	PUSHM.L	D0..D4	CALL	DIMCAMEMB	; calcul les dimensions	JUMP,NE 90$	CLR.W	D3	LOAD.L	D4,(A6)+OCMPOS	CLR.L	D0		; D0 <-- coordonne Y initiale10$:	CALL	STOPKEY		; arrt d'urgence ?	JUMP,NE 90$		; oui => 90$	CALL	ONEGCAM	CALL	TITGCAM	ADD.W	D4,(A6)+OCMDIM+2 ; D4 <-- colonne suivante	INC.W	D3	COMP.W	D3,(A6)+OCMNBX	; est-on au bout de la ligne ?	JUMP',LO 50$		; non => 50$				; oui =>	LOAD.W	D4,(A6)+OCMPOS+2	SWAP.W	D4	ADD.W	D4,(A6)+OCMDIM+0 ; D4 <-- au dbut de la ligne suivante	SWAP.W	D4	CLR.W	D350$:	SWAP.W	D0	INC.W	D0		; D0 <-- coordonne Y suivante	LOAD.W	D2,D0	SWAP.W	D0	COMP.W	D2,(A6)+ODIMY	JUMP,LO 10$	CLR.W	D7		; D7 <-- ok90$:	POPM.L	D0..D4	TEST.W	D7		; retour EQ/NE	RET;--------\\; TITGCAM >;--------/; Dessine un nom de camembert.; in	D4.L	coin sup/gauche (y;x);	D0.L	position dans tableau (y;x); out	-; mod	D7.WTITGCAM:	PUSHM.L	D0..D5,A3,A4	TEST.B	(A6)+OECFAN+2:#BECNOX	JUMP,BC 90$	LOAD.L	D5,D4	LOAD.L	A3,#R16"TGCAX	; A3 <-- ^titre gencar "Axe X"	CALL	GETTGC		; A4 <-- ^dans OBUGC	LOAD.W	D4,(A4)+OGC1Y	ADD.W	D4,(A4)+OGC2Y	; D4 <-- hauteur d'un caractre	LOAD.L	A3,#(A4)+OGCCOD	LOAD.B	(A3),#USEGC	LOAD.W	D3,#4	.W	LIB,?STRING	; utilise le bon gencar	JUMP,NE 90$	LOAD.L	D2,D0	LOAD.W	D2,#-1	CALL	GETCH		; A3 <-- ^chane	JUMP,NE 80$	LOAD.W	D4,(A6)+OCMDIM+2 ; D4 <-- lg max	CALL	GETMCH		; D3/D4 <-- nb caractres/lg de la chane	LOAD.W	D1,D3		; D1 <-- nb caractres	JUMP,EQ 80$	LOAD.L	D3,D5		; D3 <-- position	SWAP.W	D3	ADD.W	D3,(A6)+OCMDIM+2	ADD.W	D3,#2	ADD.W	D3,(A4)+OGC1Y	SWAP.W	D3	SUB.W	D4,(A6)+OCMDIM+2	NEG.W	D4	SR.W	D4,#1	ADD.W	D3,D4	.W	LIB,?SETCURS	LOAD.W	D3,D1		; D3 <-- nb de caractres	.W	LIB,?STRING	; affiche la (partie de) chane80$:	.W	LIB,?AFTIM	.B	USEGC,GCTXF,GCTXS,GCTXT,0	.EVEN90$:	POPM.L	D0..D5,A3,A4	RET;--------\\; ONEGCAM >;--------/; Dessine un camembert.; in	D4.L	coin sup/gauche (y;x);	D0.L	position dans tableau (y;x); out	-; mod	D7.WONEGCAM:	PUSHM.L	D0..D5,A4,A5	LOAD.L	A5,(A6)+OCHMATH	; A5 <-- canal interne de math64	LOAD.L	D3,(A6)+OCMDIM	SR.W	D3,#1	ADD.W	D4,D3		; D4 <-- milieu en X	SWAP.W	D3	SWAP.W	D4	SR.W	D3,#1	ADD.W	D4,D3		; D4 <-- milieu en Y;	SWAP.W	D3	SWAP.W	D4	LOAD.L	D5,D4		; D5 <-- position; Calcul la somme de tous les nombres du camembert.	CLR.W	D0		; D0 <-- coordonne X initiale	CLR.L	(A6)+OCMSOM+0	CLR.L	(A6)+OCMSOM+410$:	LOAD.L	D2,D0		; D2 <-- coordonne (y;x)	CALL	GETNB0		; D3D4 <-- nombre	JUMP',NE 20$	LOAD.L	D1,(A6)+OCMSOM+0	LOAD.L	D2,(A6)+OCMSOM+4	.W	MATH64_ADD	LOAD.L	(A6)+OCMSOM+0,D3	LOAD.L	(A6)+OCMSOM+4,D420$:	INC.W	D0		; D0 <-- coordonne X suivante	COMP.W	D0,(A6)+ODIMX	JUMP,LO 10$; Dessine le camembert.	CLR.W	D0		; D0 <-- coordonne X initiale	CLR.L	(A6)+OCMANG+0	CLR.L	(A6)+OCMANG+4	LOAD.L	A4,#(A6)+OCMTT40$:	LOAD.L	D2,D0		; D2 <-- coordonne (y;x)	CALL	GETNB0		; D3D4 <-- nombre	JUMP',NE 50$	PUSHM.L	D3,D4	LOAD.L	D4,#360	.W	MATH64_BINFP	LOAD.L	D1,D3	LOAD.L	D2,D4	POPM.L	D3,D4	.W	MATH64_MUL	LOAD.L	D1,(A6)+OCMSOM+0	LOAD.L	D2,(A6)+OCMSOM+4	.W	MATH64_DIV	; D3D4 <-- (n*360)/SOM	CALL	MEMTRANCHE	; dessine z'en une rondelle !	LOAD.L	D1,(A6)+OCMANG+0	LOAD.L	D2,(A6)+OCMANG+4	.W	MATH64_ADD	LOAD.L	(A6)+OCMANG+0,D3	LOAD.L	(A6)+OCMANG+4,D450$:	INC.W	D0		; D0 <-- coordonne X suivante	COMP.W	D0,(A6)+ODIMX	JUMP,LO 40$	LOAD.W	(A4)+OCMTTD,#-1	; OCMTT <-- terminateur	CALL	DESITRANCHE	; dessine les faces intrieures	CALL	DESETRANCHE	; dessine les faces extrieures	CALL	DESSTRANCHE	; dessine les faces suprieures	POPM.L	D0..D5,A4,A5	RET;-----------\\; MEMTRANCHE >;-----------/; Mmorise une tranche de camembert.; in	D0.L		position dans le tableau;	D3D4		angle dimensions;	(A6)+OCMANG.64	angle initial;	D5.L		position centre;	A4.L		^dans OCMTT; out	A4.L		^plus loin; mod	D7.W, A4.LMEMTRANCHE:	PUSHM.L	D0..D6	LOAD.L	D6,D0	CALL	DEFPTRAIT	; dfini le trait selon D0.L	COMP.W	D2,#-1	JUMP,EQ 90$	.W	MATH64_FPBIN	LOAD.W	D1,D4		; D1 <-- angle dimensions	LOAD.L	D3,(A6)+OCMANG+0	LOAD.L	D4,(A6)+OCMANG+4	.W	MATH64_FPBIN	LOAD.W	D0,D4		; D0 <-- angle de dpart	ADD.W	D1,D0		; D1 <-- angle d'arrive	LOAD.L	D3,D5		; D3 <-- centre (y;x)	LOAD.W	D4,(A6)+OCMDIM+2	MUL.WU	D4,#8	DIV.WU	D4,#10	SR.W	D4,#1		; D4 <-- rayon	LOAD.W	D5,D4	SWAP.W	D4	LOAD.W	D4,D5		; D4 <-- rayons (ry;dx)	TEST.B	(A6)+OPEFAN+3:#BPEOUI ; perspective ?	JUMP',BC 30$		; non => 30$				; oui =>	SWAP.W	D3	SWAP.W	D4	LOAD.W	D5,D4	MUL.WU	D5,(A6)+OPEEL	DIV.WU	D5,#100	ADD.W	D3,D5	SUB.W	D3,D4		; D3 <-- remonte un peu le centre en Y	LOAD.W	D4,D5	SWAP.W	D4	SWAP.W	D330$:	LOAD.L	D5,(A6)+ODTFAN	TEST.L	D5:D6		; tranche dcale ?	JUMP',BC 40$		; non => 40$				; oui =>	PUSHM.L	D0,D1,D4	SUB.W	D1,D0	SR.W	D1,#1	ADD.W	D0,D1		; D0 <-- alpha + bta/2	LOAD.W	D5,D4	MUL.WU	D5,#3	DIV.WU	D5,#10	LOAD.W	D4,D5	SWAP.W	D4	LOAD.W	D5,D4	MUL.WU	D5,#3	DIV.WU	D5,#10	LOAD.W	D4,D5	SWAP.W	D4	CALL	PCERCLE	LOAD.L	D3,D5		; D3 <-- nouveau point	POPM.L	D0,D1,D440$:	LOAD.W	(A4)+OCMTTD,D0	; OCMTT <-- angle de dpart	LOAD.W	(A4)+OCMTTA,D1	; OCMTT <-- angle d'arrive	LOAD.L	(A4)+OCMTTR,D4	; OCMTT <-- rayons (ry;dx)	LOAD.L	(A4)+OCMTTC,D3	; OCMTT <-- centre (y;x)	LOAD.L	(A4)+OCMTTP,D6	; OCMTT <-- position dans le tableau	LOAD.L	A4,#(A4)+LCMTT	; A4 <-- ^suivant dans OCMTT90$:	POPM.L	D0..D6	RET;------------\\; DESITRANCHE >;============/; Dessine les faces intrieures de toutes les tranches.; in	-; out	-; mod	D7.WDESITRANCHE:	PUSHM.L	D0..D6,A3,A4	TEST.B	(A6)+OPEFAN+3:#BPEOUI ; perspective ?	JUMP,BC 90$		; non => 90$; Met dans OCMTF toutes les faces intrieures  dessiner.	LOAD.L	A4,#(A6)+OCMTT	LOAD.L	A3,#(A6)+OCMTF20$:	COMP.W	(A4)+OCMTTD,#-1	; fin de la table ?	JUMP',EQ 30$		; oui => 30$				; non =>	LOAD.L	D4,(A4)+OCMTTR	; D4 <-- rayons (ry;dx)	LOAD.L	D3,(A4)+OCMTTC	; D3 <-- centre (y;x)	LOAD.W	D0,(A4)+OCMTTD	; D0 <-- angle de dpart	CALL	PCERCLE	CALL	DESTIANGLE	; D0 <-- transforme l'angle	LOAD.W	(A3)+OCMTFA,D0	; OCMTF <-- angle	LOAD.L	(A3)+OCMTFC,D3	; OCMTF <-- centre (y;x)	LOAD.L	(A3)+OCMTFP,D5	; OCMTF <-- point (y;x)	LOAD.L	A3,#(A3)+LCMTF	; A3 <-- ^suivant dans OCMTF	LOAD.W	D0,(A4)+OCMTTA	; D0 <-- angle d'arrive	CALL	PCERCLE	CALL	DESTIANGLE	; D0 <-- transforme l'angle	LOAD.W	(A3)+OCMTFA,D0	; OCMTF <-- angle	LOAD.L	(A3)+OCMTFC,D3	; OCMTF <-- centre (y;x)	LOAD.L	(A3)+OCMTFP,D5	; OCMTF <-- point (y;x)	LOAD.L	A3,#(A3)+LCMTF	; A3 <-- ^suivant dans OCMTF	LOAD.L	A4,#(A4)+LCMTT	; A4 <-- ^suivant dans OCMTT	JUMP	20$30$:	LOAD.W	(A3)+OCMTFA,#-1	; OCMTF <-- terminateur; Dessine toutes les faces contenues dans OCMTF, en commenant; par celles qui sont les plus hautes.40$:	LOAD.W	D0,#-1	LOAD.L	A3,#(A6)+OCMTF42$:	COMP.W	(A3)+OCMTFA,#-1	; fin de la table ?	JUMP',EQ 50$		; oui => 50$				; non =>	COMP.W	(A3)+OCMTFA,#-2	; face dj dessine ?	JUMP',EQ 45$		; oui => 45$				; non =>	COMP.W	D0,(A3)+OCMTFA	; angle plus petit ?	JUMP',LS 45$		; non => 45$				; oui =>	LOAD.W	D0,(A3)+OCMTFA	; D0 <-- angle le plus petit	LOAD.L	A4,A3		; A4 <-- ^face dans OCMTF45$:	LOAD.L	A3,#(A3)+LCMTF	; A3 <-- ^suivant dans OCMTF	JUMP	42$50$:	COMP.W	D0,#-1		; trouv une face ?	JUMP',EQ 90$		; non => 90$				; oui =>	LOAD.W	(A4)+OCMTFA,#-2	; signal face dj dessine	LOAD.L	D3,(A4)+OCMTFC	; D3 <-- centre (y;x)	LOAD.L	D4,(A4)+OCMTFP	; D4 <-- point (y;x)	CALL	DRPTRFIM	; masque une face intrieure	CALL	DRPTRFI		; dessine une face intrieure	JUMP	40$90$:	POPM.L	D0..D6,A3,A4	RET;-----------\\; DESTIANGLE >;-----------/; Transforme un angle comme suit :;;	I)	  0..90      -->      90..180;	II)	 90..180     -->     360..270;	III)	180..270     -->     270..180;	IV)	270..360     -->       0..90; in	D0.W	angle; out	D0.W	angle transform; mod	D0.L, D7.WDESTIANGLE:	COMP.W	D0,#270	JUMP',HS 40$	COMP.W	D0,#90	JUMP',HS 30$				; I)	ADD.W	D0,#90	JUMP'	90$30$:				; II) et III)	NEG.W	D0	ADD.W	D0,#360+90	JUMP'	90$40$:				; IV)	SUB.W	D0,#27090$:	RET;------------\\; DESETRANCHE >;============/; Dessine les faces extrieures de tous les camemberts.; in	-; out	-; mod	D7.WDESETRANCHE:	PUSHM.L	D0..D6,A4	TEST.B	(A6)+OPEFAN+3:#BPEOUI ; perspective ?	JUMP,BC 90$		; non => 90$				; oui =>	LOAD.L	A4,#(A6)+OCMTT20$:	COMP.W	(A4)+OCMTTD,#-1	; fin de la table ?	JUMP,EQ 90$		; oui => 90$				; non =>	LOAD.L	D0,(A4)+OCMTTP	; D0 <-- position dans le tableau	LOAD.L	D6,D0	CALL	DEFPTRAIT	; dfini le trait selon D0.L	COMP.W	D2,#-1	JUMP,EQ 80$	OR.W	D2,#SETDOT	LOAD.W	D0,(A4)+OCMTTD	; D0 <-- angle de dpart	LOAD.W	D1,(A4)+OCMTTA	; D1 <-- angle d'arrive	LOAD.L	D4,(A4)+OCMTTR	; D4 <-- rayons (ry;dx)	LOAD.L	D3,(A4)+OCMTTC	; D3 <-- centre (y;x)	CALL	DRPTRFEM	; masque sous la face	CALL	DRPTRFE		; dessine la face80$:	LOAD.L	A4,#(A4)+LCMTT	; A4 <-- ^suivant dans OCMTT	JUMP	20$90$:	POPM.L	D0..D6,A4	RET;------------\\; DESSTRANCHE >;============/; Dessine les faces suprieures de tous les camemberts.; in	-; out	-; mod	D7.WDESSTRANCHE:	PUSHM.L	D0..D6,A4	LOAD.L	A4,#(A6)+OCMTT20$:	COMP.W	(A4)+OCMTTD,#-1	; fin de la table ?	JUMP,EQ 90$		; oui => 90$				; non =>	LOAD.L	D0,(A4)+OCMTTP	; D0 <-- position dans le tableau	LOAD.L	D6,D0	CALL	DEFPTRAIT	; dfini le trait selon D0.L	COMP.W	D2,#-1	JUMP,EQ 80$	OR.W	D2,#SETDOT	LOAD.W	D0,(A4)+OCMTTD	; D0 <-- angle de dpart	LOAD.W	D1,(A4)+OCMTTA	; D1 <-- angle d'arrive	LOAD.L	D4,(A4)+OCMTTR	; D4 <-- rayons (ry;dx)	LOAD.L	D3,(A4)+OCMTTC	; D3 <-- centre (y;x)	TEST.B	(A6)+OPEFAN+3:#BPEOUI ; perspective ?	JUMP',BC 40$		; non => 40$				; oui =>	CALL	DRPTRFSM	; efface sous la face suprieure40$:	TSET.L	D2:#BDRTDD	TSET.L	D2:#BDRTDA	TSET.L	D2:#BDRT12	TSET.L	D2:#BDRT34	CALL	DRTRANCHE	; dessine la tranche	PUSH.L	A4	LOAD.L	A4,(A6)+OPLDEF	; A4 <-- ^trait utilis	CALL	IFCTRAIT	; dlimit par un trait continu ?	POP.L	A4	JUMP',NE 80$		; non => 80$				; oui =>	EX.L	D0,D6	CALL	DEFPTRAME	; dfini la trame selon D0.L	COMP.W	D2,#-1	JUMP',EQ 80$	EX.L	D0,D6	SUB.W	D1,D0	SR.W	D1,#1	ADD.W	D0,D1		; D0 <-- alpha + bta/2	SR.W	D4,#1		; D4 <-- rayon/2	SWAP.W	D4	SR.W	D4,#1		; D4 <-- rayon/2	SWAP.W	D4	CALL	PCERCLE	LOAD.L	D3,D5		; D3 <-- point de remplissage	CALL	DRFILL		; trame la tranche80$:	LOAD.L	A4,#(A4)+LCMTT	; A4 <-- ^suivant dans OCMTT	JUMP	20$90$:	POPM.L	D0..D6,A4	RET;----------\\; DIMCAMEMB >;==========/; Calcul les dimensions pour les camemberts.; in	-; out	(A6)+OCMPOS.L	position (y;x);	(A6)+OCMDIM.L	dimensions (dy;dx);	(A6)+OCMNBX.W	nb en largeur;	D7.W		erreur; mod	D7.WDIMCAMEMB:	PUSHM.L	D0..D4; Cherche les meilleurs dimensions en donnant priorit; au positionnement horizontal.	LOAD.W	D2,#1		; D2 <-- un en largeur20$:	CALL	EDHCAMEMB	; D1 <-- nb max possible	COMP.W	D1,(A6)+ODIMY	; est-ce assez ?	JUMP',HS 28$		; oui => 28$				; non =>	INC.W	D2		; D2 <-- un de plus en largeur	COMP.W	D2,#16	JUMP,LO 20$	CLR.L	(A6)+OCMDIM28$:	LOAD.W	D0,(A6)+OCMNBX	LOAD.L	D3,(A6)+OCMPOS	; D3 <-- position	LOAD.L	D4,(A6)+OCMDIM	; D4 <-- dimensions; Cherche les meilleurs dimensions en donnant priorit; au positionnement vertical.	LOAD.W	D2,#1		; D2 <-- un en hauteur30$:	CALL	EDVCAMEMB	; D1 <-- nb max possible	COMP.W	D1,(A6)+ODIMY	; est-ce assez ?	JUMP',HS 38$		; oui => 38$				; non =>	INC.W	D2		; D2 <-- un de plus en hauteur	COMP.W	D2,#8	JUMP,LO 30$	CLR.L	(A6)+OCMDIM38$:	COMP.W	D4,(A6)+OCMDIM+2	JUMP',HS 50$	LOAD.W	D0,(A6)+OCMNBX	LOAD.L	D3,(A6)+OCMPOS	LOAD.L	D4,(A6)+OCMDIM	; D4 <-- dimensions les plus grandes50$:	TEST.L	D4		; est-ce possible ?	JUMP',NE 80$		; oui => 80$	LOAD.W	D7,#ERGSUTP	; D7 <-- surface trop petite	JUMP'	90$80$:	LOAD.W	(A6)+OCMNBX,D0	LOAD.L	(A6)+OCMPOS,D3	LOAD.L	(A6)+OCMDIM,D4	CLR.W	D7		; D7 <-- ok90$:	POPM.L	D0..D4	TEST.W	D7		; retour EQ/NE	RET;----------\\; EDHCAMEMB >;----------/; Essaie de mettre la maximum de camemberts connaissant; le nombre en largeur.; in	D2.W	nb en largeur; out	D1.W	nb max possible; mod	D1.L, D7.WEDHCAMEMB:	PUSHM.L	D3,D4,A3,A4	LOAD.W	(A6)+OCMNBX,D2	CLR.W	D3	TEST.B	(A6)+OECFAN+2:#BECNOX	JUMP',BC 10$	LOAD.L	A3,#R16"TGCAX	; A3 <-- ^titre gencar "Axe X"	CALL	GETTGC		; A4 <-- ^dans OBUGC	LOAD.W	D3,(A4)+OGC1Y	ADD.W	D3,(A4)+OGC2Y	; D3 <-- hauteur d'un caractre10$:	CLR.L	D4	LOAD.W	D4,(A6)+ODGRAX	SUB.W	D4,(A6)+OMARGG	SUB.W	D4,(A6)+OMARGD	; D4 <-- largeur disponible	DIV.WU	D4,D2		; D4 <-- largeur	LOAD.W	D1,D4	SWAP.W	D4	LOAD.W	D4,D1		; D4 <-- hauteur	ADD.W	D4,D3		; D4 <-- hauteur + caractre	SWAP.W	D4	LOAD.W	D3,(A6)+OPBIGY	ADD.W	D3,(A6)+OMARGH	SWAP.W	D3	LOAD.W	D3,(A6)+OPBIGX	ADD.W	D3,(A6)+OMARGG	CLR.L	D1	LOAD.W	D1,(A6)+ODGRAY	SUB.W	D1,(A6)+OMARGH	SUB.W	D1,(A6)+OMARGB	; D1 <-- hauteur disponible	SWAP.W	D4	DIV.WU	D1,D4	SWAP.W	D4	SWAP.W	D1	SWAP.W	D3	SR.W	D1,#1	ADD.W	D3,D1	SWAP.W	D3	SWAP.W	D1	MUL.WU	D1,D2		; D1 <-- nb max possible	LOAD.L	(A6)+OCMPOS,D3	LOAD.L	(A6)+OCMDIM,D4	POPM.L	D3,D4,A3,A4	RET;----------\\; EDVCAMEMB >;----------/; Essaie de mettre la maximum de camemberts connaissant; le nombre en hauteur.; in	D2.W	nb en hauteur; out	D1.W	nb max possible; mod	D1.L, D7.WEDVCAMEMB:	PUSHM.L	D3,D4,A3,A4	CLR.W	D3	TEST.B	(A6)+OECFAN+2:#BECNOX	JUMP',BC 10$	LOAD.L	A3,#R16"TGCAX	; A3 <-- ^titre gencar "Axe X"	CALL	GETTGC		; A4 <-- ^dans OBUGC	LOAD.W	D3,(A4)+OGC1Y	ADD.W	D3,(A4)+OGC2Y	; D3 <-- hauteur d'un caractre10$:	CLR.L	D4	LOAD.W	D4,(A6)+ODGRAY	SUB.W	D4,(A6)+OMARGH	SUB.W	D4,(A6)+OMARGB	; D4 <-- hauteur disponible	DIV.WU	D4,D2		; D4 <-- hauteur	LOAD.W	D1,D4	SWAP.W	D4	LOAD.W	D4,D1		; D4 <-- largeur	SUB.W	D4,D3		; D4 <-- largeur - caractre	LOAD.W	D3,(A6)+OPBIGY	ADD.W	D3,(A6)+OMARGH	SWAP.W	D3	LOAD.W	D3,(A6)+OPBIGX	ADD.W	D3,(A6)+OMARGG	CLR.L	D1	LOAD.W	D1,(A6)+ODGRAX	SUB.W	D1,(A6)+OMARGG	SUB.W	D1,(A6)+OMARGD	; D1 <-- largeur disponible	DIV.WU	D1,D4	LOAD.W	(A6)+OCMNBX,D1	SWAP.W	D1	SR.W	D1,#1	ADD.W	D3,D1	SWAP.W	D1	MUL.WU	D1,D2		; D1 <-- nb max possible	LOAD.L	(A6)+OCMPOS,D3	LOAD.L	(A6)+OCMDIM,D4	POPM.L	D3,D4,A3,A4	RET;---------\\; DRPTRFIM >;=========/; Masque une face intrieure (paralllogramme).; in	D3.L	centre (y;x);	D4.L	point (y;x);	D5.W	hauteur; out	-; mod	D7.WDRPTRFIM:	PUSHM.L	D0..D6,A3,A4	COMP.W	D3,D4	JUMP,EQ 90$	SUB.W	D3,(A6)+OPBIGX	SWAP.W	D3	SUB.W	D3,(A6)+OPBIGY	SWAP.W	D3	SUB.W	D4,(A6)+OPBIGX	SWAP.W	D4	SUB.W	D4,(A6)+OPBIGY	SWAP.W	D4	CALL	CLRDISMAT	CALL	OPEDISMAT	LOAD.W	D2,#SETDOT	CALL	DRPTRFI		; dessine le pourtour	COMP.W	D3,D4	JUMP',LS 20$	LOAD.W	D2,D3	LOAD.W	D3,D4		; EX.W D3,D4	LOAD.W	D4,D220$:	SWAP.W	D3	SWAP.W	D4	COMP.W	D3,D4	JUMP',LS 25$	LOAD.W	D2,D3	LOAD.W	D3,D4		; EX.W D3,D4	LOAD.W	D4,D225$:	SWAP.W	D3	SWAP.W	D4	SUB.W	D4,D3		; D4 <-- dx	SWAP.W	D3	SWAP.W	D4	SUB.W	D4,D3	ADD.W	D4,D5		; D4 <-- dy	SWAP.W	D3	SWAP.W	D4	PUSHM.L	D3,D4	LOAD.L	D3,#-1	LOAD.L	D4,D3	CALL	DRTRADEF	POPM.L	D3,D4	PUSHM.L	D3,D4	SR.W	D4,#1	ADD.W	D3,D4	SWAP.W	D3	SWAP.W	D4	SR.W	D4,#1	ADD.W	D3,D4	SWAP.W	D3	SWAP.W	D4	CALL	DRFILL	POPM.L	D3,D4	CALL	CLODISMAT; Efface l'ombre de la face dans l'cran.	LOAD.L	D1,D4		; D1 <-- dimensions;	LOAD.L	D3,D3		; D3 <-- source: (y;x)	LOAD.L	A3,(A6)+OPMAT	LOAD.W	D5,(A6)+ODBIGX	SR.W	D5,#3	LOAD.L	D4,D3		; D4 <-- destination: (y;x)	ADD.W	D4,(A6)+OPBIGX	SWAP.W	D4	ADD.W	D4,(A6)+OPBIGY	SWAP.W	D4	LOAD.L	A4,#0	CLR.W	D6	LOAD.W	D2,#CLRDOT	CALL	DRRASTER	; efface dans l'cran90$:	POPM.L	D0..D6,A3,A4	RET;--------\\; DRPTRFI >;========/     ; Dessine une face intrieure (paralllogramme).; in	D3.L	centre (y;x);	D4.L	point (y;x);	D5.W	hauteur; out	-; mod	D7.WDRPTRFI:	PUSHM.L	D3..D5	SUB.W	D4,D3		; D4 <-- dx	JUMP,EQ 90$	SWAP.W	D4	SWAP.W	D3	SUB.W	D4,D3		; D4 <-- dy	SWAP.W	D4	SWAP.W	D3	CALL	DRLINE	PUSH.L	D4	LOAD.W	D4,D5	NEG.W	D4	SWAP.W	D4	CLR.W	D4	CALL	DRLINE	POP.L	D4	NEG.W	D4	SWAP.W	D4	NEG.W	D4	SWAP.W	D4	CALL	DRLINE;	PUSH.L	D4	LOAD.W	D4,D5	SWAP.W	D4	CLR.W	D4	CALL	DRLINE;	POP.L	D490$:	POPM.L	D3..D5	RET;---------\\; DRPTRFEM >;=========/; Masque la ou les faces extrieures.; in	D0.W	angle de dpart (0..360);	D1.W	angle d'arrive (0..360);	D2.W	mode;	D3.L	centre (y;x);	D4.L	rayons (ry;rx);	D5.W	paisseur; out	-; mod	D7.WDRPTRFEM:	PUSHM.L	D0..D6,A3,A4	COMP.W	D0,#180	JUMP',LO 20$	COMP.W	D1,#180	JUMP',LO 20$	COMP.W	D1,#360	JUMP,LO 90$20$:	SUB.W	D3,(A6)+OPBIGX	SWAP.W	D3	SUB.W	D3,(A6)+OPBIGY	SWAP.W	D3	CALL	CLRDISMAT	CALL	OPEDISMAT	LOAD.W	D2,#SETDOT	CALL	DRPTRFE		; dessine le ou les pourtours	SUB.W	D3,D4		; D3 <-- coin sup/droite	SL.W	D4,#1	ADD.W	D4,D3	SWAP.W	D3	SWAP.W	D4	ADD.W	D4,D3	ADD.W	D4,D5		; D4 <-- coin inf/gauche	SWAP.W	D4	SWAP.W	D3	SUB.W	D3,#4	AND.B	D3,#B'11111000	; D3 <-- x	ADD.W	D4,#4	SUB.W	D4,D3	ADD.W	D4,#8-1	AND.B	D4,#B'11111000	; D4 <-- dx	SWAP.W	D3	SWAP.W	D4	SUB.W	D3,#4	AND.B	D3,#B'11111110	; D3 <-- y	ADD.W	D4,#4	SUB.W	D4,D3	ADD.W	D4,#2-1	AND.B	D4,#B'11111110	; D4 <-- dy	SWAP.W	D3	SWAP.W	D4	CALL	DRRECT		; met un rectangle autour	PUSHM.L	D3,D4	LOAD.L	D3,#-1	LOAD.L	D4,D3	CALL	DRTRADEF	POPM.L	D3,D4	PUSH.L	D3	ADD.W	D3,#2	SWAP.W	D3	ADD.W	D3,#2	SWAP.W	D3	CALL	DRFILL		; rempli l'extrieur	POP.L	D3	LOAD.L	A3,(A6)+OPMAT	; A3 <-- ^matrice	CALL	EFFINVLIGNE	; inverse le tout	CALL	CLODISMAT; Efface l'ombre de la face dans l'cran.	LOAD.L	D1,D4		; D1 <-- dimensions;	LOAD.L	D3,D3		; D3 <-- source: (y;x)	LOAD.L	A3,(A6)+OPMAT	LOAD.W	D5,(A6)+ODBIGX	SR.W	D5,#3	LOAD.L	D4,D3		; D4 <-- destination: (y;x)	ADD.W	D4,(A6)+OPBIGX	SWAP.W	D4	ADD.W	D4,(A6)+OPBIGY	SWAP.W	D4	LOAD.L	A4,#0	CLR.W	D6	LOAD.W	D2,#CLRDOT	CALL	DRRASTER	; efface dans l'cran90$:	POPM.L	D0..D6,A3,A4	RET;--------\\; DRPTRFE >;========/; Dessine la ou les faces extrieures.; in	D0.W	angle de dpart (0..360);	D1.W	angle d'arrive (0..360);	D2.W	mode;	D3.L	centre (y;x);	D4.L	rayons (ry;rx);	D5.W	paisseur; out	-; mod	D7.WDRPTRFE:	PUSH.L	D2	TCLR.L	D2:#BDRTDD	TCLR.L	D2:#BDRTDA	TSET.L	D2:#BDRT12	TCLR.L	D2:#BDRT34	CALL	DRTRANCHE	PUSH.L	D3	SWAP.W	D3	ADD.W	D3,D5	SWAP.W	D3	CALL	DRTRANCHE	POP.L	D3	CALL	DRPTRFEVD	; dessine la verticale au dpart	CALL	DRPTRFEVA	; dessine la verticale  l'arrive	CALL	DRPTRFEVL	; dessine la verticale  gauche	CALL	DRPTRFEVR	; dessine la verticale  droite	POP.L	D2	RET;----------\\; DRPTRFEVD >;----------/; Dessine la droite verticale de dpart.; in	D0.W	angle de dpart (0..360);	D1.W	angle d'arrive (0..360);	D2.W	mode;	D3.L	centre (y;x);	D4.L	rayons (ry;rx);	D5.W	paisseur; out	-; mod	D7.WDRPTRFEVD:	PUSHM.L	D3..D5	COMP.W	D0,#180	JUMP',HS 90$				; I) ou II)	PUSH.L	D5	CALL	PCERCLE	LOAD.L	D3,D5	POP.L	D5	LOAD.W	D4,D5	SWAP.W	D4	CLR.W	D4	CALL	DRLINE		; dessine la ligne Vd90$:	POPM.L	D3..D5	RET;----------\\; DRPTRFEVA >;----------/; Dessine la droite verticale d'arrive.; in	D0.W	angle de dpart (0..360);	D1.W	angle d'arrive (0..360);	D2.W	mode;	D3.L	centre (y;x);	D4.L	rayons (ry;rx);	D5.W	paisseur; out	-; mod	D7.WDRPTRFEVA:	PUSHM.L	D0,D3..D5	CLR.L	D0	LOAD.W	D0,D1		; D0 <-- angle d'arrive	DIV.WU	D0,#360	SWAP.W	D0	COMP.W	D0,#180	JUMP',HS 90$				; I) ou II)	PUSH.L	D5	CALL	PCERCLE	LOAD.L	D3,D5	POP.L	D5	LOAD.W	D4,D5	SWAP.W	D4	CLR.W	D4	CALL	DRLINE		; dessine la ligne Va90$:	POPM.L	D0,D3..D5	RET;----------\\; DRPTRFEVL >;----------/; Dessine la droite verticale  gauche.; in	D0.W	angle de dpart (0..360);	D1.W	angle d'arrive (0..360);	D2.W	mode;	D3.L	centre (y;x);	D4.L	rayons (ry;rx);	D5.W	paisseur; out	-; mod	D7.WDRPTRFEVL:	PUSHM.L	D3,D4	COMP.W	D0,#180	JUMP',HS 32$	COMP.W	D1,#180	JUMP',HS 34$32$:	COMP.W	D0,#360+180	JUMP',HS 90$	COMP.W	D1,#360+180	JUMP',LO 90$34$:	SUB.W	D3,D4	LOAD.W	D4,D5	INC.W	D4	SWAP.W	D4	CLR.W	D4	CALL	DRLINE		; dessine la droite Vl90$:	POPM.L	D3,D4	RET;----------\\; DRPTRFEVR >;----------/; Dessine la droite verticale  droite.; in	D0.W	angle de dpart (0..360);	D1.W	angle d'arrive (0..360);	D2.W	mode;	D3.L	centre (y;x);	D4.L	rayons (ry;rx);	D5.W	paisseur; out	-; mod	D7.WDRPTRFEVR:	PUSHM.L	D3,D4	COMP.W	D0,#0	JUMP',HS 42$	COMP.W	D1,#0	JUMP',HS 44$42$:	COMP.W	D0,#360+0	JUMP',HS 90$	COMP.W	D1,#360+0	JUMP',LO 90$44$:	ADD.W	D3,D4	LOAD.W	D4,D5	INC.W	D4	SWAP.W	D4	CLR.W	D4	CALL	DRLINE		; dessine la droite Vr90$:	POPM.L	D3,D4	RET;---------\\; DRPTRFSM >;=========/; Masque une face suprieure.; in	D0.W	angle de dpart (0..360);	D1.W	angle d'arrive (0..360);	D2.W	mode + flags (BDRT..);	D3.L	centre (y;x);	D4.L	rayons (ry;rx);	D5.W	paisseur; out	-; mod	D7.WDRPTRFSM:	PUSHM.L	D0..D6,A3,A4	SUB.W	D3,(A6)+OPBIGX	SWAP.W	D3	SUB.W	D3,(A6)+OPBIGY	SWAP.W	D3	CALL	CLRDISMAT	CALL	OPEDISMAT	LOAD.L	D2,#SETDOT	TSET.L	D2:#BDRTDD	TSET.L	D2:#BDRTDA	TSET.L	D2:#BDRT12	TSET.L	D2:#BDRT34	CALL	DRTRANCHE	; dessine le pourtour de la face	PUSHM.L	D3,D4	LOAD.L	D3,#-1	LOAD.L	D4,D3	CALL	DRTRADEF	POPM.L	D3,D4	PUSHM.L	D0,D1,D3,D4	SUB.W	D1,D0	SR.W	D1,#1	ADD.W	D0,D1		; D0 <-- alpha + bta/2	SR.W	D4,#1		; D4 <-- rayon/2	SWAP.W	D4	SR.W	D4,#1		; D4 <-- rayon/2	SWAP.W	D4	CALL	PCERCLE	LOAD.L	D3,D5		; D3 <-- point de remplissage	CALL	DRFILL		; trame la tranche	POPM.L	D0,D1,D3,D4	CALL	CLODISMAT; Efface l'ombre de la face dans l'cran.	LOAD.L	D1,D4	SL.W	D1,#1	ADD.W	D1,#2+2	SWAP.W	D1	SL.W	D1,#1	ADD.W	D1,#2+2	SWAP.W	D1		; D1 <-- dimensions	SUB.W	D3,D4	SUB.W	D3,#2	SWAP.W	D3	SWAP.W	D4	SUB.W	D3,D4	SUB.W	D3,#2	SWAP.W	D3		; D3 <-- source: (y;x);	SWAP.W	D4	LOAD.L	A3,(A6)+OPMAT	LOAD.W	D5,(A6)+ODBIGX	SR.W	D5,#3	LOAD.L	D4,D3		; D4 <-- destination: (y;x)	ADD.W	D4,(A6)+OPBIGX	SWAP.W	D4	ADD.W	D4,(A6)+OPBIGY	SWAP.W	D4	LOAD.L	A4,#0	CLR.W	D6	LOAD.W	D2,#CLRDOT	CALL	DRRASTER	; efface dans l'cran	POPM.L	D0..D6,A3,A4	RET;----------\\; DRTRANCHE >;==========/; Dessine une tranche de gteau.; in	D0.W	angle de dpart (0..360);	D1.W	angle d'arrive (0..360);	D2.W	mode + flags (BDRT..);	D3.L	centre (y;x);	D4.L	rayons (ry;rx); out	-; mod	D7.WDRTRANCHE:	PUSHM.L	D0..D6	TSET.L	D2:#BNCTDOT	; D2 <-- pas de rz du traitill	TEST.L	D2:#BDRTDA	JUMP',BC 10$	PUSHM.L	D0,D3,D4	LOAD.W	D0,D1	CALL	PCERCLE	LOAD.L	D4,D5	EX.L	D3,D4	SUB.W	D4,D3		; D4 <-- dx	SWAP.W	D4	SWAP.W	D3	SUB.W	D4,D3		; D4 <-- dy	SWAP.W	D4	SWAP.W	D3	CALL	DRLINE		; dessine la droite Da	POPM.L	D0,D3,D410$:	TEST.L	D2:#BDRTDD	JUMP',BC 15$	PUSHM.L	D0,D3,D4	CALL	PCERCLE	LOAD.L	D4,D5	SUB.W	D4,D3		; D4 <-- dx	SWAP.W	D4	SWAP.W	D3	SUB.W	D4,D3		; D4 <-- dy	SWAP.W	D4	SWAP.W	D3	CALL	DRLINE		; dessine la droite Dd	POPM.L	D0,D3,D415$:	TEST.L	D2:#BDRT12	JUMP',BS 30$	TEST.L	D2:#BDRT34	JUMP,BC 90$				; arc dans III et IV =>	COMP.W	D0,#180	JUMP',HS 22$	LOAD.W	D0,#18022$:	COMP.W	D1,#180	JUMP',HS 23$	LOAD.W	D1,#18023$:	COMP.W	D0,D1	JUMP,EQ 90$	PUSH.W	D1	COMP.W	D1,#360	JUMP',LS 25$	LOAD.W	D1,#36025$:	CALL	DRARC	POP.W	D1	COMP.W	D1,#360+180	JUMP,LS 90$	LOAD.W	D0,#360+180	CALL	DRARC	JUMP	90$30$:	TEST.L	D2:#BDRT34	JUMP',BS 40$				; arc dans I et II =>	COMP.W	D0,#180	JUMP',LS 32$	LOAD.W	D0,#36032$:	COMP.W	D1,#360	JUMP',LO 33$	COMP.W	D1,#360+180	JUMP',LS 34$	LOAD.W	D1,#360+180	JUMP'	34$33$:	COMP.W	D1,#180	JUMP',LS 34$	LOAD.W	D1,#18034$:	COMP.W	D0,D1	JUMP,HS 90$	PUSH.W	D1	COMP.W	D0,#360	JUMP',EQ 35$	COMP.W	D1,#180	JUMP',LS 35$	LOAD.W	D1,#18035$:	CALL	DRARC	POP.W	D1	COMP.W	D0,#360	JUMP,EQ 90$	COMP.W	D1,#360	JUMP,LS 90$	LOAD.W	D0,#360	CALL	DRARC	JUMP	90$40$:	CALL	DRARC90$:	POPM.L	D0..D6	RET;--------\\; DRARC   >;========/; Dessine un arc de cercle.; in	D0.W	angle de dpart (0..360);	D1.W	angle d'arrive (0..360);	D2.W	mode;	D3.L	centre (y;x);	D4.L	rayons (ry;rx); out	-; mod	D7.WDRARC:	PUSHM.L	D0..D6	TSET.L	D2:#BNCTDOT	; D2 <-- pas de rz du traitill	CLR.L	D6		; D6 <-- position initiale	LOAD.L	D5,#4*(360/6)	; D5 <-- L*(360/2PI)	DIV.WU	D5,D4	TEST.W	D5	JUMP',NE 20$	INC.W	D520$:	PUSHM.L	D3..D5	CALL	PCERCLE		; D5 <-- nouveau point	LOAD.L	D3,D6	JUMP',NE 30$	LOAD.L	D6,D5	JUMP'	35$30$:	LOAD.L	D4,D5	SUB.W	D4,D3		; D4 <-- dx	SWAP.W	D4	SWAP.W	D3	SUB.W	D4,D3		; D4 <-- dy	SWAP.W	D4	SWAP.W	D3	CALL	DRLINE	LOAD.L	D6,D3		; D6 <-- position suivante35$:	POPM.L	D3..D5	COMP.W	D0,D1	JUMP',HS 90$	ADD.W	D0,D5		; D0 <-- angle suivant	COMP.W	D0,D1	JUMP,LS 20$	LOAD.W	D0,D1	JUMP	20$90$:	POPM.L	D0..D6	RET;--------\\; PCERCLE >;--------/; Calcul les coordonnes d'un point situ sur un cercle.; in	D0.W	angle;	D3.L	centre (y;x);	D4.L	rayons (ry;rx); out	D5.L	point (y;x); mod	D5.L, D7.WPCERCLE:	PUSH.L	D1	CALL	SINUS	SWAP.W	D4	MUL.WA	D1,D4	SWAP.W	D4	ADD.L	D1,#1000/2	DIV.WA	D1,#1000	SWAP.W	D3	ADD.W	D1,D3	SWAP.W	D3	LOAD.W	D5,D1	SWAP.W	D5	CALL	COSINUS	MUL.WA	D1,D4	ADD.L	D1,#1000/2	DIV.WA	D1,#1000	ADD.W	D1,D3	LOAD.W	D5,D1	POP.L	D1	RET;--------\\; COSINUS >;--------/; Calcul rapidement un cosinus.; in	D0.W	angle (0..360); out	D1.W	cosinus (-1000..+1000); mod	D1.L, D7.WCOSINUS:	PUSH.L	D0	AND.L	D0,#H'FFFF	DIV.WU	D0,#360	SWAP.W	D0		; D0 <-- 0..360-1	SUB.W	D0,#90	NEG.W	D0	JUMP',NC 50$	ADD.W	D0,#36050$:	CALL	SINUS	POP.L	D0	RET;--------\\; SINUS   >;--------/; Calcul rapidement un sinus.; in	D0.W	angle (0..360); out	D1.W	sinus (-1000..+1000); mod	D1.L, D7.WSINUS:	PUSHM.L	D0,A3	LOAD.L	A3,#R16"TSINUS	AND.L	D0,#H'FFFF	DIV.WU	D0,#360	SWAP.W	D0		; D0 <-- 0..360-1	COMP.W	D0,#90	JUMP',LS 40$	COMP.W	D0,#180	JUMP',LS 30$	COMP.W	D0,#270	JUMP',LS 20$				; angle 270..360 =>	SUB.W	D0,#360	NEG.W	D0	SL.W	D0,#1	LOAD.W	D1,(A3)+(D0.W)	NEG.W	D1	JUMP'	90$20$:				; angle 180..270 =>	SUB.W	D0,#180	SL.W	D0,#1	LOAD.W	D1,(A3)+(D0.W)	NEG.W	D1	JUMP'	90$30$:				; angle 90..180 =>	SUB.W	D0,#180	NEG.W	D0	SL.W	D0,#1	LOAD.W	D1,(A3)+(D0.W)	JUMP'	90$40$:				; angle 0..90 =>	SL.W	D0,#1	LOAD.W	D1,(A3)+(D0.W);	JUMP'	90$90$:	POPM.L	D0,A3	RETTSINUS:	.W	0,18,35,52,70,87,105,122,139,156	.W	174,191,208,225,242,259,276,292,309,326	.W	342,358,375,391,407,423,438,454,470,485	.W	500,515,530,545,559,574,588,602,616,629	.W	643,656,669,682,695,707,719,731,743,755	.W	766,777,788,799,809,819,829,839,848,857	.W	866,875,883,891,899,906,914,921,927,934	.W	940,946,951,956,961,966,970,974,978,982	.W	985,988,990,993,995,996,998,999,999,1000	.W	1000	.END